const morgan = require('morgan');

const app = express();

// Security headers
app.use(helmet());

// Request logging
app.use(morgan('combined'));

// CORS - restrict to known origins
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || false,
  methods: ['GET'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));

// Rate limiting
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

