const app = express();

// Security headers
app.use(helmet());

// Request logging
app.use(morgan('combined'));

// CORS - restrict to trusted origins
app.use(cors({
  origin: process.env.ALLOWED_ORIGIN || 'https://your-trusted-domain.com',
  methods: ['GET'],
}));

// Rate limiting
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// Body parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Routes ---

