    return res.status(401).json({ error: 'Authentication required' });
  }
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid token' });
  }
};

app.get('/users', authenticate, (req, res) => { /* ... */ });
```

---

### 5. No CORS Configuration (OWASP A05: Security Misconfiguration)

Without explicit CORS configuration, the default behavior is to reject cross-origin browser requests — but this is fragile. If a middleware or proxy changes this, the API is open to cross-origin abuse.

**Recommendation:** Explicitly configure CORS with an allowlist.

```js
